import { format } from "date-fns";
import { Trash2, Edit, Check } from "lucide-react";
import { Fragment } from "react";

import { Button } from "@/components/ui/button";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Separator } from "@/components/ui/separator";

import { formatFileSize, isImageFile } from "./utils";

import type { FsFile } from "fastschema";

interface FileDetailsProps {
  file: FsFile | null;
  onDelete?: (file: FsFile) => void;
  onEdit?: (file: FsFile) => void;
  onSelect?: (file: FsFile) => void;
  showSelectButton?: boolean;
  uploadComponent?: React.ReactNode;
}

export function FileDetails({
  file,
  onDelete,
  onEdit,
  onSelect,
  showSelectButton = false,
  uploadComponent,
}: FileDetailsProps) {
  return (
    <div className="flex h-full flex-col overflow-hidden">
      <ScrollArea className="min-h-0 flex-1">
        <div className="flex flex-col gap-6 p-4">
          {uploadComponent && (
            <div className="flex flex-col gap-4">{uploadComponent}</div>
          )}

          {file ? (
            <Fragment>
              {isImageFile(file) && file.url && (
                <div className="bg-muted aspect-video w-full overflow-hidden rounded-lg">
                  <img
                    src={file.url}
                    alt={file.name}
                    className="h-full w-full object-cover"
                  />
                </div>
              )}

              <div className="flex flex-col gap-2 text-sm">
                <div className="flex items-center justify-between">
                  <span className="text-muted-foreground">Filename</span>
                  <span className="text-right font-medium break-all">
                    {file.name}
                  </span>
                </div>
                <Separator />
                <div className="flex items-center justify-between">
                  <span className="text-muted-foreground">File Type</span>
                  <span className="font-medium capitalize">
                    {file.type.split("/")[0]}
                  </span>
                </div>
                <Separator />
                <div className="flex items-center justify-between">
                  <span className="text-muted-foreground">Upload Date</span>
                  <span className="font-medium">
                    {file.created_at
                      ? format(new Date(file.created_at), "MMMM d, yyyy")
                      : "Unknown"}
                  </span>
                </div>
                <Separator />
                <div className="flex items-center justify-between">
                  <span className="text-muted-foreground">File Size</span>
                  <span className="font-medium">
                    {formatFileSize(file.size)}
                  </span>
                </div>
                {isImageFile(file) && file.url && (
                  <Fragment>
                    <Separator />
                    <div className="flex items-center justify-between">
                      <span className="text-muted-foreground">URL</span>
                      <a
                        href={file.url}
                        target="_blank"
                        rel="noopener noreferrer"
                        className="text-primary text-right font-medium break-all hover:underline"
                      >
                        View
                      </a>
                    </div>
                  </Fragment>
                )}
              </div>

              <div className="flex flex-col gap-3 pt-2">
                <div className="grid grid-cols-2 gap-3">
                  {showSelectButton && onSelect && (
                    <Button
                      onClick={() => onSelect(file)}
                      className="w-full"
                      size="sm"
                    >
                      <Check className="size-4" />
                      Select File
                    </Button>
                  )}
                  {onEdit && (
                    <Button
                      variant="outline"
                      size="sm"
                      onClick={() => onEdit(file)}
                      className="w-full"
                    >
                      <Edit className="size-4" />
                      Edit
                    </Button>
                  )}
                  {onDelete && (
                    <Button
                      variant="destructive"
                      size="sm"
                      onClick={() => onDelete(file)}
                      className="w-full"
                    >
                      <Trash2 className="size-4" />
                      Delete
                    </Button>
                  )}
                </div>
              </div>
            </Fragment>
          ) : (
            <div className="text-muted-foreground flex flex-col items-center justify-center py-12 text-center">
              <p>Select a file to view details</p>
            </div>
          )}
        </div>
      </ScrollArea>
    </div>
  );
}

import { Image as ImageIcon, Video, FileText, File } from "lucide-react";
import { Fragment, useMemo } from "react";

import { cn } from "@/lib/utils";

import { Loading } from "../fscommon";

import { isImageFile, getFileIcon } from "./utils";

import type { FsFile } from "fastschema";

const iconMap = {
  image: ImageIcon,
  video: Video,
  "file-text": FileText,
  file: File,
};

interface FileGridProps {
  files: FsFile[];
  selectedFileId?: number;
  selectedFileIds?: number[];
  onFileSelect?: (file: FsFile) => void;
  isLoading?: boolean;
  columns?: number;
  selectionMode?: "single" | "multiple";
}

export function FileGrid({
  files,
  selectedFileId,
  selectedFileIds,
  onFileSelect,
  isLoading = false,
  columns = 5,
  selectionMode = "single",
}: FileGridProps) {
  const gridCols = useMemo(() => {
    const colsMap: Record<number, string> = {
      2: "grid-cols-2",
      3: "grid-cols-3",
      4: "grid-cols-4",
      5: "grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5",
      6: "grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-6",
    };
    return (
      colsMap[columns] ||
      "grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5"
    );
  }, [columns]);

  if (isLoading) {
    return <Loading />;
  }

  if (files.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center py-12 text-center">
        <File className="text-muted-foreground mb-4 size-12" />
        <p className="text-muted-foreground">No files found</p>
      </div>
    );
  }

  return (
    <div className={cn("grid gap-4", gridCols)}>
      {files.map((file) => {
        const isSelected =
          selectionMode === "multiple"
            ? (selectedFileIds?.includes(file.id as number) ?? false)
            : selectedFileId === file.id;
        const Icon =
          iconMap[getFileIcon(file.type) as keyof typeof iconMap] || File;

        return (
          <div
            key={file.id}
            className="group flex cursor-pointer flex-col gap-2"
            onClick={() => onFileSelect?.(file)}
          >
            <div
              className={cn(
                "relative aspect-square w-full overflow-hidden rounded-lg",
                "bg-muted border-2 transition-all",
                isSelected
                  ? "border-primary ring-primary ring-2 ring-offset-2"
                  : "group-hover:border-primary/50 border-transparent",
              )}
            >
              {isImageFile(file) && file.url ? (
                <Fragment>
                  <img
                    src={file.url}
                    alt={file.name}
                    className="h-full w-full object-cover"
                  />
                  {isSelected && (
                    <div className="bg-primary/20 absolute inset-0" />
                  )}
                </Fragment>
              ) : (
                <div className="bg-muted flex h-full w-full items-center justify-center">
                  <Icon className="text-muted-foreground size-12" />
                </div>
              )}
              {isSelected && (
                <div className="bg-primary absolute top-2 right-2 flex size-5 items-center justify-center rounded-full text-white">
                  <svg
                    className="size-3"
                    fill="none"
                    stroke="currentColor"
                    viewBox="0 0 24 24"
                  >
                    <path
                      strokeLinecap="round"
                      strokeLinejoin="round"
                      strokeWidth={2}
                      d="M5 13l4 4L19 7"
                    />
                  </svg>
                </div>
              )}
            </div>
            <p className="truncate text-center text-xs font-medium">
              {file.name}
            </p>
          </div>
        );
      })}
    </div>
  );
}

import {
  Image as ImageIcon,
  Video,
  FileText,
  File,
  Trash2,
} from "lucide-react";

import { Button } from "@/components/ui/button";
import { Skeleton } from "@/components/ui/skeleton";
import { cn } from "@/lib/utils";

import { formatFileSize, getFileIcon, isImageFile } from "./utils";

import type { FsFile } from "fastschema";

const iconMap = {
  image: ImageIcon,
  video: Video,
  "file-text": FileText,
  file: File,
};

interface FileListProps {
  files: FsFile[];
  selectedFileId?: number;
  selectedFileIds?: number[];
  onFileSelect?: (file: FsFile) => void;
  onFileDelete?: (file: FsFile) => void;
  isLoading?: boolean;
  selectionMode?: "single" | "multiple";
}

export function FileList({
  files,
  selectedFileId,
  selectedFileIds,
  onFileSelect,
  onFileDelete,
  isLoading = false,
  selectionMode = "single",
}: FileListProps) {
  if (isLoading) {
    return (
      <div className="space-y-2">
        {Array.from({ length: 10 }).map((_, i) => (
          <div
            // eslint-disable-next-line react/no-array-index-key
            key={i}
            className="flex items-center gap-4 rounded-lg border p-3"
          >
            <Skeleton className="size-12 rounded" />
            <div className="flex-1 space-y-2">
              <Skeleton className="h-4 w-48" />
              <Skeleton className="h-3 w-32" />
            </div>
          </div>
        ))}
      </div>
    );
  }

  if (files.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center py-12 text-center">
        <File className="text-muted-foreground mb-4 size-12" />
        <p className="text-muted-foreground">No files found</p>
      </div>
    );
  }

  return (
    <div className="space-y-2">
      {files.map((file) => {
        const isSelected =
          selectionMode === "multiple"
            ? (selectedFileIds?.includes(file.id as number) ?? false)
            : selectedFileId === file.id;
        const Icon =
          iconMap[getFileIcon(file.type) as keyof typeof iconMap] || File;

        return (
          <div
            key={file.id}
            className={cn(
              "flex cursor-pointer items-center gap-4 rounded-lg border p-3 transition-colors",
              isSelected ? "bg-primary/10 border-primary" : "hover:bg-muted/50",
            )}
            onClick={() => onFileSelect?.(file)}
          >
            <div className="bg-muted relative size-12 flex-shrink-0 overflow-hidden rounded">
              {isImageFile(file) && file.url ? (
                <img
                  src={file.url}
                  alt={file.name}
                  className="h-full w-full object-cover"
                />
              ) : (
                <div className="flex h-full w-full items-center justify-center">
                  <Icon className="text-muted-foreground size-6" />
                </div>
              )}
            </div>
            <div className="min-w-0 flex-1">
              <p className="truncate text-sm font-medium">{file.name}</p>
              <p className="text-muted-foreground text-xs">
                {formatFileSize(file.size)} • {file.type}
              </p>
            </div>
            {onFileDelete && (
              <Button
                variant="ghost"
                size="icon-sm"
                className="size-8"
                onClick={(e) => {
                  e.stopPropagation();
                  onFileDelete(file);
                }}
              >
                <Trash2 className="size-4" />
              </Button>
            )}
          </div>
        );
      })}
    </div>
  );
}

import { PinIcon, PinOffIcon } from "lucide-react";

import { Button } from "@/components/ui/button";
import { Tabs, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { AlertError, Loading } from "@/components/fsui/fscommon";

import { FsDialog } from "../fscommon/dialog";

import { FileDetails } from "./file-details";
import { FileGrid } from "./file-grid";
import { FileList as FileListView } from "./file-list";
import { FileToolbar } from "./file-toolbar";
import { FileUpload } from "./file-upload";
import { useFilePickerTab } from "./hooks/use-file-picker-tab";
import { Pagination } from "./pagination";

import type { FsFile, PKType, FileTypeFilter } from "fastschema";

export interface FilePickerModalProps {
  open?: boolean;
  onOpenChange?: (open: boolean) => void;
  onFileSelect?: (file: FsFile | FsFile[]) => void;
  selectionMode?: "single" | "multiple";
  allowedFileType?: FileTypeFilter;
  schemaName?: string;
  pkValue?: PKType;
  fieldName?: string;
  backRefFieldName?: string;
  onAttachDetachComplete?: () => void;
}

export function FilePickerModal({
  open,
  onOpenChange,
  onFileSelect,
  selectionMode = "single",
  allowedFileType,
  schemaName,
  pkValue,
  fieldName,
  backRefFieldName,
  onAttachDetachComplete,
}: FilePickerModalProps) {
  const tab = useFilePickerTab({
    open,
    selectionMode,
    allowedFileType,
    schemaName,
    pkValue,
    fieldName,
    backRefFieldName,
    onFileSelect,
    onOpenChange,
    onAttachDetachComplete,
  });

  if (tab.error) {
    return (
      <FsDialog
        open={open}
        onOpenChange={onOpenChange}
        title="File Picker"
      >
        <AlertError error={tab.error} />
      </FsDialog>
    );
  }

  const renderPagination = () => (
    <Pagination
      currentPage={tab.currentPage}
      totalPages={tab.totalPages}
      onPageChange={tab.setPage}
    />
  );

  const renderActions = () => {
    if (tab.isEditMode) {
      const isAttached = tab.activeTab === "attached";
      const Icon = isAttached ? PinOffIcon : PinIcon;
      const label = isAttached ? "Detach" : "Attach";
      const handler = isAttached ? tab.handleDetach : tab.handleAttach;
      return (
        <Button
          size="sm"
          variant={isAttached ? "outline" : "default"}
          className="gap-2"
          onClick={handler}
          disabled={tab.selectedFiles.length === 0 || tab.isMutating}
        >
          <Icon className="size-4" /> {label} ({tab.selectedFiles.length})
        </Button>
      );
    }
    if (tab.selectedFiles.length > 0) {
      return (
        <Button
          onClick={tab.handleSelectClick}
          size="sm"
        >
          Select {tab.selectedFiles.length} File
          {tab.selectedFiles.length > 1 ? "s" : ""}
        </Button>
      );
    }
    return null;
  };

  return (
    <FsDialog
      open={open}
      onOpenChange={onOpenChange}
      hideCloseButton={true}
      contentClassName="h-[90vh] md:h-[90vh] md:max-h-[90vh] lg:h-[90vh] max-h-[90vh] sm:max-w-[90vw] lg:max-w-[1400px]"
      title={
        <div className="flex w-full items-center gap-4">
          {tab.isEditMode && (
            <Tabs
              value={tab.activeTab}
              onValueChange={tab.handleTabChange}
            >
              <TabsList>
                <TabsTrigger value="attached">Attached</TabsTrigger>
                <TabsTrigger value="available">Available</TabsTrigger>
              </TabsList>
            </Tabs>
          )}
          <div className="flex-1">
            <FileToolbar
              search={tab.search}
              onSearchChange={tab.setSearch}
              viewMode={tab.viewMode}
              onViewModeChange={tab.setViewMode}
              fileTypeFilter={tab.fileTypeFilter}
              onFileTypeFilterChange={tab.setFileTypeFilter}
              sort={tab.sort}
              onSortChange={tab.setSort}
            />
          </div>
        </div>
      }
      actions={{ left: renderPagination(), right: renderActions() }}
    >
      <div className="flex max-h-[90vh] flex-col gap-0 overflow-hidden p-0 sm:max-w-[90vw] lg:max-w-[1400px]">
        <div
          className="flex min-h-0 flex-1 flex-col overflow-hidden"
          style={{ height: "80vh", maxHeight: "80vh" }}
        >
          <div className="flex min-h-0 flex-1 overflow-hidden">
            <div className="flex min-w-0 flex-1 flex-col overflow-hidden border-r">
              <div className="min-h-0 flex-1 overflow-y-auto p-4">
                {tab.isLoading ? (
                  <Loading />
                ) : tab.viewMode === "grid" ? (
                  <FileGrid
                    files={tab.files}
                    selectedFileId={tab.selectedFile?.id}
                    selectedFileIds={
                      selectionMode === "multiple"
                        ? tab.selectedFiles.map((f) => f.id as number)
                        : undefined
                    }
                    onFileSelect={tab.handleFileClick}
                    isLoading={false}
                    selectionMode={selectionMode}
                  />
                ) : (
                  <FileListView
                    files={tab.files}
                    selectedFileId={tab.selectedFile?.id}
                    onFileSelect={tab.handleFileClick}
                    onFileDelete={tab.handleDelete}
                    isLoading={false}
                  />
                )}
              </div>
            </div>
            <aside className="flex w-[350px] flex-shrink-0 flex-col overflow-hidden border-l">
              <FileDetails
                file={tab.selectedFile}
                onDelete={tab.handleDelete}
                onSelect={tab.handleFileClick}
                showSelectButton={!!tab.selectedFile && !tab.isEditMode}
                uploadComponent={
                  tab.activeTab === "available" ? (
                    <FileUpload
                      onUpload={tab.handleUpload}
                      className="h-32"
                      multiple
                    />
                  ) : undefined
                }
              />
            </aside>
          </div>
        </div>
      </div>
    </FsDialog>
  );
}

import { Grid3x3, List, Search, Upload } from "lucide-react";

import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { ToggleGroup, ToggleGroupItem } from "@/components/ui/toggle-group";

import type { FileListViewMode, FileTypeFilter } from "fastschema";

interface FileToolbarProps {
  search: string;
  onSearchChange: (search: string) => void;
  viewMode: FileListViewMode;
  onViewModeChange: (mode: FileListViewMode) => void;
  fileTypeFilter: FileTypeFilter;
  onFileTypeFilterChange: (filter: FileTypeFilter) => void;
  onUploadClick?: () => void;
  sort?: string;
  onSortChange?: (sort: string) => void;
}

export function FileToolbar({
  search,
  onSearchChange,
  viewMode,
  onViewModeChange,
  fileTypeFilter,
  onFileTypeFilterChange,
  onUploadClick,
  sort,
  onSortChange,
}: FileToolbarProps) {
  return (
    <div className="flex flex-col items-center gap-4 p-0 md:flex-row">
      <div className="w-full md:flex-1">
        <div className="relative">
          <Search className="text-muted-foreground absolute top-1/2 left-3 size-4 -translate-y-1/2" />
          <Input
            placeholder="Search for media..."
            name="search_media"
            value={search}
            onChange={(e) => onSearchChange(e.target.value)}
            className="pl-9"
          />
        </div>
      </div>
      <div className="flex w-full items-center gap-4 md:w-auto">
        <ToggleGroup
          type="single"
          value={fileTypeFilter}
          onValueChange={(value) => {
            if (value) {
              onFileTypeFilterChange(value as FileTypeFilter);
            }
          }}
          className="bg-muted flex h-10 w-full rounded-lg p-1 md:w-auto"
        >
          <ToggleGroupItem
            value="all"
            aria-label="All files"
            className="flex-1 md:flex-none"
            size="sm"
          >
            All
          </ToggleGroupItem>
          <ToggleGroupItem
            value="image"
            aria-label="Images"
            className="flex-1 md:flex-none"
          >
            Images
          </ToggleGroupItem>
          <ToggleGroupItem
            value="video"
            aria-label="Videos"
            className="flex-1 md:flex-none"
            size="sm"
          >
            Videos
          </ToggleGroupItem>
          <ToggleGroupItem
            value="audio"
            aria-label="Audio"
            className="flex-1 md:flex-none"
            size="sm"
          >
            Audio
          </ToggleGroupItem>
          <ToggleGroupItem
            value="document"
            aria-label="Documents"
            className="flex-1 md:flex-none"
            size="sm"
          >
            Docs
          </ToggleGroupItem>
        </ToggleGroup>
        <div className="bg-muted flex gap-1 rounded-lg p-1">
          <Button
            variant={viewMode === "grid" ? "default" : "ghost"}
            size="icon-sm"
            className="size-8"
            onClick={() => onViewModeChange("grid")}
          >
            <Grid3x3 className="size-4" />
          </Button>
          <Button
            variant={viewMode === "list" ? "default" : "ghost"}
            size="icon-sm"
            className="size-8"
            onClick={() => onViewModeChange("list")}
          >
            <List className="size-4" />
          </Button>
        </div>
        {onSortChange && (
          <Select
            value={sort}
            onValueChange={onSortChange}
          >
            <SelectTrigger className="w-[140px]">
              <SelectValue placeholder="Sort by" />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="-id">Newest first</SelectItem>
              <SelectItem value="id">Oldest first</SelectItem>
              <SelectItem value="name">Name A-Z</SelectItem>
              <SelectItem value="-name">Name Z-A</SelectItem>
              <SelectItem value="size">Size (smallest)</SelectItem>
              <SelectItem value="-size">Size (largest)</SelectItem>
            </SelectContent>
          </Select>
        )}
        {onUploadClick && (
          <Button
            onClick={onUploadClick}
            size="sm"
          >
            <Upload className="size-4" />
            Upload
          </Button>
        )}
      </div>
    </div>
  );
}

import { Upload, CloudUpload } from "lucide-react";
import { useRef, useState, useCallback } from "react";

import { Button } from "@/components/ui/button";
import { cn } from "@/lib/utils";

interface FileUploadProps {
  onUpload: (files: File[]) => Promise<void>;
  className?: string;
  multiple?: boolean;
  accept?: string;
}

export function FileUpload({
  onUpload,
  className,
  multiple = true,
  accept,
}: FileUploadProps) {
  const [isDragging, setIsDragging] = useState(false);
  const [isUploading, setIsUploading] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleDragOver = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDragging(true);
  }, []);

  const handleDragLeave = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDragging(false);
  }, []);

  const handleDrop = useCallback(
    async (e: React.DragEvent) => {
      e.preventDefault();
      e.stopPropagation();
      setIsDragging(false);

      const files = Array.from(e.dataTransfer.files);
      if (files.length > 0) {
        setIsUploading(true);
        try {
          await onUpload(files);
        } finally {
          setIsUploading(false);
        }
      }
    },
    [onUpload],
  );

  const handleFileSelect = useCallback(
    async (e: React.ChangeEvent<HTMLInputElement>) => {
      const files = Array.from(e.target.files || []);
      if (files.length > 0) {
        setIsUploading(true);
        try {
          await onUpload(files);
        } finally {
          setIsUploading(false);
          if (fileInputRef.current) {
            fileInputRef.current.value = "";
          }
        }
      }
    },
    [onUpload],
  );

  const handleClick = useCallback(() => {
    fileInputRef.current?.click();
  }, []);

  return (
    <div
      className={cn(
        "relative flex flex-col items-center justify-center rounded-xl border-1 border-dashed p-4 text-center transition-colors",
        isDragging
          ? "border-primary bg-primary/10"
          : "border-muted-foreground/25 bg-muted/50",
        className,
      )}
      onDragOver={handleDragOver}
      onDragLeave={handleDragLeave}
      onDrop={handleDrop}
    >
      <input
        ref={fileInputRef}
        type="file"
        multiple={multiple}
        accept={accept}
        onChange={handleFileSelect}
        className="hidden"
      />
      <CloudUpload className="text-muted-foreground mb-2 size-8" />
      <p className="mb-1 text-sm font-medium">
        {isDragging ? "Drop files here" : "Drag & drop files here"}
      </p>
      <p className="text-muted-foreground mb-3 text-xs">or click to browse</p>
      <Button
        type="button"
        variant="outline"
        size="sm"
        onClick={handleClick}
        disabled={isUploading}
      >
        <Upload className="size-4" />
        {isUploading ? "Uploading..." : "Browse Files"}
      </Button>
    </div>
  );
}

import { useFastSchema } from "fastschema/react";
import { useState, useEffect, useMemo, useRef } from "react";

import type { Filter, Pagination, FsFile } from "fastschema";

function getFilterKey(filter: Filter | undefined): string {
  if (!filter) return "";
  try {
    return JSON.stringify(filter, Object.keys(filter).sort());
  } catch {
    return JSON.stringify(filter);
  }
}

export function useFileList({
  page = 1,
  limit = 20,
  filter,
  sort,
  search,
}: {
  page?: number;
  limit?: number;
  filter?: Filter;
  sort?: string;
  search?: string;
}) {
  const { fastschema } = useFastSchema();
  const [refreshId, setRefreshId] = useState(0);
  const [content, setContent] = useState<{
    error?: Error;
    result?: Pagination<FsFile>;
    key?: string;
  }>({});
  const prevParamsRef = useRef<string>("");

  const filesFilter: Filter | undefined = useMemo(() => {
    if (search) {
      return {
        $and: [
          filter ?? {},
          {
            name: {
              $like: `%${search}%`,
            },
          },
        ],
      };
    }
    return filter;
  }, [search, filter]);

  const schema = fastschema.schema("file");

  const queryKey = useMemo(() => {
    const filterKey = getFilterKey(filesFilter);
    return `${page}-${limit}-${filterKey}-${sort || ""}-${search || ""}`;
  }, [page, limit, filesFilter, sort, search]);

  const fetchKey = `${queryKey}-${refreshId}`;
  const isFetching = content.key !== fetchKey;
  const isLoading = isFetching && !content.result;

  useEffect(() => {
    if (prevParamsRef.current === queryKey && content.key === fetchKey) {
      return;
    }

    prevParamsRef.current = queryKey;
    let cancelled = false;

    if (!schema) {
      setContent({
        error: new Error(`Schema not found: file`),
        key: fetchKey,
      });
      return;
    }

    (async () => {
      try {
        const rs = await schema.get<FsFile>({
          page,
          limit,
          filter: filesFilter,
          sort,
        });
        if (!cancelled) {
          setContent({
            result: rs,
            key: fetchKey,
          });
        }
      } catch (error) {
        if (!cancelled) {
          setContent({
            error: error as Error,
            key: fetchKey,
          });
        }
      }
    })();

    return () => {
      cancelled = true;
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [fetchKey]);

  return {
    error: content?.error,
    result: content?.result,
    isLoading,
    isFetching,
    reFetch: () => setRefreshId((v) => v + 1),
  };
}

import { useFastSchema } from "fastschema/react";
import { useCallback, useState } from "react";
import { toast } from "sonner";

import type { FsFile } from "fastschema";

export interface UseFileOperationsOptions {
  selectionMode?: "single" | "multiple";
  selectedFiles?: FsFile[];
  setSelectedFiles?: (files: FsFile[] | ((prev: FsFile[]) => FsFile[])) => void;
  onRefetch?: () => void;
}

export interface UseFileOperationsReturn {
  isUploading: boolean;
  handleUpload: (files: File[]) => Promise<void>;
  handleDelete: (file: FsFile) => Promise<void>;
}

export function useFileOperations({
  selectionMode = "single",
  selectedFiles = [],
  setSelectedFiles,
  onRefetch,
}: UseFileOperationsOptions): UseFileOperationsReturn {
  const { fastschema } = useFastSchema();
  const [isUploading, setIsUploading] = useState(false);

  const handleUpload = useCallback(
    async (files: File[]) => {
      setIsUploading(true);
      try {
        const uploadResult = await fastschema.file().upload(files);
        if (uploadResult.success.length > 0) {
          toast.success(
            `Successfully uploaded ${uploadResult.success.length} file(s)`,
          );
          onRefetch?.();
          if (uploadResult.success.length === 1 && setSelectedFiles) {
            const uploadedFile = uploadResult.success[0] as FsFile;
            if (selectionMode === "single") {
              setSelectedFiles([uploadedFile]);
            } else {
              setSelectedFiles((prev) => [...prev, uploadedFile]);
            }
          }
        }
        if (uploadResult.error.length > 0) {
          toast.error(`Failed to upload ${uploadResult.error.length} file(s)`);
        }
      } catch (error) {
        toast.error(`Upload failed: ${(error as Error).message}`);
      } finally {
        setIsUploading(false);
      }
    },
    [fastschema, onRefetch, selectionMode, setSelectedFiles],
  );

  const handleDelete = useCallback(
    async (file: FsFile) => {
      if (!file.id) {
        return;
      }

      // eslint-disable-next-line no-alert
      if (!confirm(`Are you sure you want to delete "${file.name}"?`)) {
        return;
      }

      const wasSelected = selectedFiles.some((f) => f.id === file.id);
      if (wasSelected && setSelectedFiles) {
        setSelectedFiles((prev) => prev.filter((f) => f.id !== file.id));
      }

      try {
        await fastschema.schema("file")?.delete(file.id);
        toast.success("File deleted successfully");
        onRefetch?.();
      } catch (error) {
        // Revert optimistic update on error
        if (wasSelected && setSelectedFiles) {
          setSelectedFiles((prev) => [...prev, file]);
        }
        toast.error(`Delete failed: ${(error as Error).message}`);
      }
    },
    [fastschema, onRefetch, selectedFiles, setSelectedFiles],
  );

  return {
    isUploading,
    handleUpload,
    handleDelete,
  };
}

import {
  type FsFile,
  type FileTypeFilter,
  type FileListViewMode,
  type PKType,
  createFileTypeFilter,
  createRelationFileFilter,
} from "fastschema";
import { useContentList, useFastSchema } from "fastschema/react";
import { useState, useCallback, useMemo, useEffect } from "react";
import { toast } from "sonner";

import { useFileOperations } from "./use-file-operations";

type PickerTab = "attached" | "available";

export interface UseFilePickerTabOptions {
  open?: boolean;
  limit?: number;
  selectionMode?: "single" | "multiple";
  allowedFileType?: FileTypeFilter;
  // Edit mode props
  schemaName?: string;
  pkValue?: PKType;
  fieldName?: string;
  backRefFieldName?: string;
  // Callbacks
  onFileSelect?: (file: FsFile | FsFile[]) => void;
  onOpenChange?: (open: boolean) => void;
  onAttachDetachComplete?: () => void;
}

export function useFilePickerTab({
  open,
  limit = 20,
  selectionMode = "single",
  allowedFileType = "all",
  schemaName,
  pkValue,
  fieldName,
  backRefFieldName,
  onFileSelect,
  onOpenChange,
  onAttachDetachComplete,
}: UseFilePickerTabOptions) {
  const { fastschema } = useFastSchema();
  const isEditMode = Boolean(
    pkValue && schemaName && fieldName && backRefFieldName,
  );

  const [activeTab, setActiveTab] = useState<PickerTab>("available");
  const [page, setPage] = useState(1);
  const [search, setSearch] = useState("");
  const [sort, setSort] = useState<string>("-id");
  const [viewMode, setViewMode] = useState<FileListViewMode>("grid");
  const [selectedFiles, setSelectedFiles] = useState<FsFile[]>([]);
  const [isMutating, setIsMutating] = useState(false);
  const [fileTypeFilter, setFileTypeFilter] = useState(allowedFileType);
  const relationFilter = createRelationFileFilter({
    isEditMode,
    mode: activeTab,
    backRefFieldName,
    pkValue,
    typeFilter: createFileTypeFilter(fileTypeFilter),
  });

  const filter = useMemo(() => {
    if (!search) {
      return relationFilter;
    }
    const searchFilter = { name: { $like: `%${search}%` } };
    if (!relationFilter) {
      return searchFilter;
    }
    return { $and: [relationFilter, searchFilter] };
  }, [relationFilter, search]);

  const { result, isLoading, isFetching, error, reFetch } =
    useContentList<FsFile>({
      schemaName: "file",
      page,
      limit,
      filter,
      sort,
      // Disable attached tab fetch in create mode
      dummy: !isEditMode && activeTab === "attached",
    });

  // Reset state when modal opens
  useEffect(() => {
    if (open) {
      setSelectedFiles([]);
      setActiveTab(isEditMode ? "attached" : "available");
      setPage(1);
    }
  }, [open, isEditMode]);

  // File operations hook
  const { handleUpload, handleDelete } = useFileOperations({
    selectionMode,
    selectedFiles,
    setSelectedFiles,
    onRefetch: reFetch,
  });

  // Computed values
  const selectedFile =
    selectionMode === "single" ? selectedFiles[0] || null : null;

  // Search change with page reset
  const handleSearchChange = useCallback((value: string) => {
    setSearch(value);
    setPage(1);
  }, []);

  // Sort change with page reset
  const handleSortChange = useCallback((value: string) => {
    setSort(value);
    setPage(1);
  }, []);

  // File type filter change with page reset
  const handleFileTypeFilterChange = useCallback((value: FileTypeFilter) => {
    setFileTypeFilter(value);
    setPage(1);
  }, []);

  // File click handler
  const handleFileClick = useCallback(
    (file: FsFile) => {
      if (selectionMode === "single") {
        setSelectedFiles([file]);
      } else {
        setSelectedFiles((prev) => {
          const isSelected = prev.some((f) => f.id === file.id);
          return isSelected
            ? prev.filter((f) => f.id !== file.id)
            : [...prev, file];
        });
      }
    },
    [selectionMode],
  );

  // Tab change handler
  const handleTabChange = useCallback((tabValue: string) => {
    setActiveTab(tabValue as PickerTab);
    setSelectedFiles([]);
    setPage(1);
  }, []);

  // Attach/Detach handler
  const handleAttachDetach = useCallback(
    async (operation: "$add" | "$clear") => {
      if (
        !isEditMode ||
        selectedFiles.length === 0 ||
        !schemaName ||
        !fieldName
      ) {
        return;
      }
      setIsMutating(true);
      try {
        const schema = fastschema.schema(schemaName);
        await schema?.update(pkValue as PKType, {
          [fieldName]: {
            [operation]: selectedFiles.map((f) => ({ id: f.id })),
          },
        });
        toast.success(
          `Successfully ${operation === "$add" ? "attached" : "detached"} ${selectedFiles.length} file(s)`,
        );
        setSelectedFiles([]);
        reFetch();
        onAttachDetachComplete?.();
        onOpenChange?.(false);
      } catch (error_) {
        toast.error(
          `Failed to ${operation === "$add" ? "attach" : "detach"} files: ${(error_ as Error).message}`,
        );
      } finally {
        setIsMutating(false);
      }
    },
    [
      isEditMode,
      selectedFiles,
      schemaName,
      fieldName,
      pkValue,
      fastschema,
      reFetch,
      onAttachDetachComplete,
      onOpenChange,
    ],
  );

  const handleAttach = useCallback(
    () => handleAttachDetach("$add"),
    [handleAttachDetach],
  );
  const handleDetach = useCallback(
    () => handleAttachDetach("$clear"),
    [handleAttachDetach],
  );

  // Select click handler (create mode)
  const handleSelectClick = useCallback(() => {
    if (selectedFiles.length === 0) {
      return;
    }
    onFileSelect?.(
      selectionMode === "single" ? selectedFiles[0] : selectedFiles,
    );
    onOpenChange?.(false);
  }, [selectedFiles, selectionMode, onFileSelect, onOpenChange]);

  return {
    // Mode
    isEditMode,
    activeTab,

    // Data
    files: (result?.items ?? []) as FsFile[],
    total: result?.total ?? 0,
    error,

    // Loading states
    isLoading,
    isFetching,
    isMutating,

    // Selection
    selectedFiles,
    selectedFile,

    // Pagination
    page,
    setPage,
    totalPages: result?.last_page ?? 1,
    currentPage: result?.current_page ?? 1,

    // Search
    search,
    setSearch: handleSearchChange,

    // Sort
    sort,
    setSort: handleSortChange,

    // View mode
    viewMode,
    setViewMode,

    // File type filter
    fileTypeFilter,
    setFileTypeFilter: handleFileTypeFilterChange,

    // Actions
    reFetch,
    handleFileClick,
    handleTabChange,
    handleAttach,
    handleDetach,
    handleSelectClick,
    handleUpload,
    handleDelete,
  };
}

