} from "fastschema";

export interface MediaLibraryProps {
  page?: number;
  limit?: number;
  filter?: Filter;
  onPaginationChange?: (page: number, limit: number) => void;
  onFileSelect?: (file: FsFile | FsFile[]) => void;
  onSelectedFilesChange?: (files: FsFile[]) => void;
  onBulkDelete?: (files: FsFile[]) => void;
  onRefetch?: () => void;
  showDetailsSidebar?: boolean;
  showUploadInSidebar?: boolean;
  showUploadOnTop?: boolean;
  mode?: "page" | "modal";
  selectionMode?: "single" | "multiple";
  selectedFiles?: FsFile[];
}

const typeMap: Record<FileTypeFilter, string> = {
  all: "",
  image: "image/",
  video: "video/",
  audio: "audio/",
  document: "application/",
};

export function MediaLibrary({
  page = 1,
  limit = 20,
  filter,
  onPaginationChange,
  onFileSelect,
  onSelectedFilesChange,
  showDetailsSidebar = true,
  showUploadInSidebar = true,
  showUploadOnTop = false,
  mode = "page",
  selectionMode = "single",
  selectedFiles: controlledSelectedFiles,
}: MediaLibraryProps) {
  const [search, setSearch] = useState("");
  const [viewMode, setViewMode] = useState<FileListViewMode>("grid");
  const [fileTypeFilter, setFileTypeFilter] = useState<FileTypeFilter>("all");
  const [sort, setSort] = useState<string>("-id");
  const [internalSelectedFiles, setInternalSelectedFiles] = useState<FsFile[]>(
    [],
  );

  const selectedFiles = controlledSelectedFiles ?? internalSelectedFiles;
  const selectedFile =
    selectionMode === "single" ? selectedFiles[0] || null : null;
  const combinedFilter: Filter | undefined = useMemo(() => {
    const filters: Filter[] = [];

    // Add base filter if provided
    if (filter) {
      filters.push(filter);
    }

    // Add file type filter
    if (fileTypeFilter !== "all") {
      const typePrefix = typeMap[fileTypeFilter];
      filters.push({
        type: {
          $like: `${typePrefix}%`,
        },
      });
    }

    // Add search filter
    if (search) {
      filters.push({
        name: {
          $like: `%${search}%`,
        },
      });
    }

    if (filters.length === 0) {
      return undefined;
    }

    if (filters.length === 1) {
      return filters[0];
    }

    return {
      $and: filters,
    };
  }, [fileTypeFilter, filter, search]);

  const { result, isLoading, isFetching, error, reFetch } =
    useContentList<FsFile>({
      schemaName: "file",
      page,
      limit,
      filter: combinedFilter,
      sort,
    });

  const { handleUpload, handleDelete } = useFileOperations({
    selectionMode,
    selectedFiles,
    setSelectedFiles: setInternalSelectedFiles,
    onRefetch: reFetch,
  });

  const handleFileSelect = useCallback(
    (file: FsFile) => {
      if (selectionMode === "single") {
        const newSelection = [file];
        setInternalSelectedFiles(newSelection);
        onFileSelect?.(file);
        onSelectedFilesChange?.(newSelection);
      } else {
        const isSelected = selectedFiles.some((f) => f.id === file.id);
        let newSelection: FsFile[];
        if (isSelected) {
          newSelection = selectedFiles.filter((f) => f.id !== file.id);
        } else {
          newSelection = [...selectedFiles, file];
        }
        setInternalSelectedFiles(newSelection);
        onFileSelect?.(newSelection);
        onSelectedFilesChange?.(newSelection);
      }
    },
    [onFileSelect, onSelectedFilesChange, selectionMode, selectedFiles],
  );

  const handlePageChange = useCallback(
    (newPage: number) => {
      onPaginationChange?.(newPage, limit);
    },
    [limit, onPaginationChange],
  );

  if (error) {
    return <AlertError error={error} />;
  }

  const files = result?.items ?? [];
  const totalPages = result?.last_page ?? 1;
  const currentPage = result?.current_page ?? 1;

  const toolbar = (
    <FileToolbar
      search={search}
      onSearchChange={setSearch}
      viewMode={viewMode}
      onViewModeChange={setViewMode}
      fileTypeFilter={fileTypeFilter}
      onFileTypeFilterChange={setFileTypeFilter}
      sort={sort}
      onSortChange={setSort}
    />
  );

  if (mode === "modal") {
    return (
      <div className="grid min-h-0 flex-1 grid-cols-1 overflow-hidden lg:grid-cols-[1fr,350px]">
        <div className="flex flex-col overflow-hidden border-r">
          <div className="flex-1 overflow-y-auto p-4">
            {isLoading ? (
              <Loading />
            ) : viewMode === "grid" ? (
              <FileGrid
                files={files}
                selectedFileId={selectedFile?.id}
                onFileSelect={handleFileSelect}
                isLoading={isFetching}
              />
            ) : (
              <FileListView
                files={files}
                selectedFileId={selectedFile?.id}
                onFileSelect={handleFileSelect}
                onFileDelete={handleDelete}
                isLoading={isFetching}
              />
            )}
          </div>
        </div>

        {showDetailsSidebar && (
          <aside className="w-full flex-shrink-0 overflow-hidden border-l">
            <FileDetails
              file={selectedFile}
              onDelete={handleDelete}
              onSelect={onFileSelect ? handleFileSelect : undefined}
              showSelectButton={!!onFileSelect && !!selectedFile}
              uploadComponent={
                showUploadInSidebar ? (
                  <FileUpload
                    onUpload={handleUpload}
                    className="h-32"
                    multiple
                  />
                ) : undefined
              }
            />
          </aside>
        )}
      </div>
    );
  }

  // Page mode - include pagination in the component
  return (
    <div className="flex h-full min-h-0 flex-col">
      <div className="p-4">{toolbar}</div>

      <div className="grid min-h-0 flex-1 grid-cols-1 overflow-hidden lg:grid-cols-[1fr,350px]">
        <div className="flex flex-col overflow-hidden border-r">
          {showUploadOnTop && (
            <div className="flex-shrink-0 border-b p-4">
              <div className="flex flex-col gap-4">
                <FileUpload
                  onUpload={handleUpload}
                  className="h-32"
                  multiple
                />
              </div>
            </div>
          )}
          <div className="flex-1 overflow-y-auto p-4">
            {isLoading ? (
              <Loading />
            ) : viewMode === "grid" ? (
              <FileGrid
                files={files}
                selectedFileId={selectedFile?.id}
                selectedFileIds={
                  selectionMode === "multiple"
                    ? selectedFiles.map((f) => f.id as number).filter(Boolean)
                    : undefined
                }
                onFileSelect={handleFileSelect}
                isLoading={isFetching}
                selectionMode={selectionMode}
              />
            ) : (
              <FileListView
                files={files}
                selectedFileId={selectedFile?.id}
                selectedFileIds={
                  selectionMode === "multiple"
                    ? selectedFiles.map((f) => f.id as number).filter(Boolean)
                    : undefined
                }
                onFileSelect={handleFileSelect}
                onFileDelete={handleDelete}
                isLoading={isFetching}
                selectionMode={selectionMode}
              />
            )}
          </div>

          {/* Pagination */}
          {totalPages > 1 && (
            <div className="bg-background sticky bottom-0 flex flex-shrink-0 justify-center border-t p-4">
              <Pagination
                currentPage={currentPage}
                totalPages={totalPages}
                onPageChange={handlePageChange}
              />
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

import { ChevronLeft, ChevronRight } from "lucide-react";

import { Button } from "@/components/ui/button";

export interface PaginationProps {
  currentPage: number;
  totalPages: number;
  onPageChange: (page: number) => void;
}

/**
 * Generates an array of page numbers to display in pagination.
 * Shows up to 7 page numbers with smart windowing around the current page.
 */
function getPageNumbers(currentPage: number, totalPages: number): number[] {
  return Array.from({ length: Math.min(totalPages, 7) }, (_, i) => {
    if (totalPages <= 7) {
      return i + 1;
    }
    if (currentPage <= 4) {
      return i + 1;
    }
    if (currentPage >= totalPages - 3) {
      return totalPages - 6 + i;
    }
    return currentPage - 3 + i;
  });
}

export function Pagination({
  currentPage,
  totalPages,
  onPageChange,
}: PaginationProps) {
  if (totalPages <= 1) {
    return null;
  }

  const pages = getPageNumbers(currentPage, totalPages);

  return (
    <div className="flex items-center justify-center gap-1">
      <Button
        variant="ghost"
        size="icon-sm"
        disabled={currentPage === 1}
        onClick={() => onPageChange(currentPage - 1)}
      >
        <ChevronLeft className="size-4" />
      </Button>
      {pages.map((pageNum) => (
        <Button
          key={pageNum}
          variant={currentPage === pageNum ? "default" : "ghost"}
          size="sm"
          className="min-w-8"
          onClick={() => onPageChange(pageNum)}
        >
          {pageNum}
        </Button>
      ))}
      {totalPages > 7 && currentPage < totalPages - 3 && (
        <span className="text-muted-foreground px-2">...</span>
      )}
      {totalPages > 7 && (
        <Button
          variant="ghost"
          size="sm"
          className="min-w-8"
          onClick={() => onPageChange(totalPages)}
        >
          {totalPages}
        </Button>
      )}
      <Button
        variant="ghost"
        size="icon-sm"
        disabled={currentPage === totalPages}
        onClick={() => onPageChange(currentPage + 1)}
      >
        <ChevronRight className="size-4" />
      </Button>
    </div>
  );
}

import type { FsFile } from "fastschema";

export function formatFileSize(bytes: number): string {
  if (bytes === 0) return "0 Bytes";
  const k = 1024;
  const sizes = ["Bytes", "KB", "MB", "GB"];
  const i = Math.floor(Math.log(bytes) / Math.log(k));
  return `${Math.round((bytes / Math.pow(k, i)) * 100) / 100} ${sizes[i]}`;
}

export function getFileTypeCategory(
  type: string,
): "image" | "video" | "document" | "other" {
  const mimeType = type.toLowerCase();
  if (mimeType.startsWith("image/")) return "image";
  if (mimeType.startsWith("video/")) return "video";
  if (
    mimeType.includes("pdf") ||
    mimeType.includes("document") ||
    mimeType.includes("text") ||
    mimeType.includes("word") ||
    mimeType.includes("excel") ||
    mimeType.includes("powerpoint")
  ) {
    return "document";
  }
  return "other";
}

export function getFileIcon(type: string): string {
  const category = getFileTypeCategory(type);
  switch (category) {
    case "image": {
      return "image";
    }
    case "video": {
      return "video";
    }
    case "document": {
      return "file-text";
    }
    default: {
      return "file";
    }
  }
}

export function isImageFile(file: FsFile): boolean {
  return getFileTypeCategory(file.type) === "image";
}
